<template>
    <div class="register-client">
        <form class="client-form">
            <div class="form__title">регистрация клиента</div>
            
            <input type="text" name="company" placeholder="Компания" v-model.trim="company" :class="{error: ($v.company.$dirty && !$v.company.required) || ($v.company.$dirty && !$v.company.minLength)}">
            <label 
                    class="error"
                    v-if="$v.company.$dirty && !$v.company.required">
                    Поле 'Компания' не должно быть пустым
                </label>
                <label 
                    class="error"
                    v-else-if="$v.company.$dirty && !$v.company.minLength">
                    Значение должен быть не меньше 6 символов
                </label>

            <input type="text" name="place" placeholder="Регион" v-model.trim="place" :class="{error: ($v.place.$dirty && !$v.place.required)}">
            <label 
                    class="error"
                    v-if="$v.place.$dirty && !$v.place.required">
                    Поле 'Регион' не должно быть пустым
                </label>

            <input type="date" name="presentationDate"  class="presentationDate" placeholder="Дата Презентации дд.мм.гггг" v-model.trim="presentationDate"  :class="{error: ($v.place.$dirty && !$v.place.required)}">
            <label 
                    class="error"
                    v-if="$v.presentationDate.$dirty && !$v.presentationDate.required">
                    Поле 'Дата Презентации' не должно быть пустым
                </label>

            <input type="submit" value="начать презентацию" id="registerClient" v-on:click.prevent = "sendForm">
        </form>
    </div>
</template>
<script>
import {email, required, minLength} from 'vuelidate/lib/validators'; //валидатор

export default {
    name: 'registerClient',
    data: () => ({
        company: '',
        place: '',
        presentationDate: '2013-01-08'
    }),
    validations: {
        company: {required, minLength: minLength(3)},
        place: {required},
        presentationDate: {required},
    },
    methods: {
        sendForm(){
            let self = this;
            
            if(this.$v.$invalid){
                this.$v.$touch()
                return
                
            }else{
                let data = {
                    "title": this.company,
                    "region": this.place,
                    "phone": "",
                    "email": "",
                    "description": ""
                };
                this.$store.dispatch('CLIENT_ADD', data)
                .then(response => {
                    if(response.status === 200){
                        self.$router.push('/collections');
                    }
                })
                .catch(err => console.log(err));
            }
        }
    },
    created(){
        if(localStorage.getItem('clientID') !== null){
            this.$store.dispatch('CLIENT_INFO');
            this.$router.push('/collections');
        }
        //Автозаполнение поля "дата презентации" на текущую дату
        let options = {
            year: 'numeric',
            month: 'numeric',
            day: 'numeric',
            timezone: 'UTC'
        };
        let date = new Date().toLocaleString("ru", options);
        function reformatDate(dateStr){  //разворот даты в формат гггг мм дд, т.к. input по-другому не понимает
            let dArr = dateStr.split(".");
            return dArr[2] + "-" + dArr[1] + "-" + dArr[0]
        }
        this.presentationDate = reformatDate(date)
    
    }
}
</script>
<style lang="scss" scoped>
    .presentationDate::-webkit-inner-spin-button{
        display: none;
    }
   
</style>